#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100000
#define INF 1000000000

// Define the structure for an edge
typedef struct {
    int u, v, c;
} Edge;

// Define the structure for a disjoint set
typedef struct {
    int parent[MAX], rank[MAX];
} DisjointSet;

// Function to find the parent of a node in the disjoint set
int find(DisjointSet *ds, int node) {
    if (ds->parent[node] != node) {
        ds->parent[node] = find(ds, ds->parent[node]);
    }
    return ds->parent[node];
}

// Function to union two nodes in the disjoint set
void unionSet(DisjointSet *ds, int node1, int node2) {
    int parent1 = find(ds, node1);
    int parent2 = find(ds, node2);
    if (ds->rank[parent1] < ds->rank[parent2]) {
        ds->parent[parent1] = parent2;
    } else if (ds->rank[parent1] > ds->rank[parent2]) {
        ds->parent[parent2] = parent1;
    } else {
        ds->parent[parent2] = parent1;
        ds->rank[parent1]++;
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M1, M2;
        scanf("%d %d %d", &N, &M1, &M2);
        Edge edges[M1 + M2];
        for (int i = 0; i < M1; i++) {
            scanf("%d %d %d", &edges[i].u, &edges[i].v, &edges[i].c);
        }
        for (int i = M1; i < M1 + M2; i++) {
            scanf("%d %d %d", &edges[i].u, &edges[i].v, &edges[i].c);
        }
        // Sort the edges in non-decreasing order of their weights
        for (int i = 0; i < M1 + M2; i++) {
            for (int j = i + 1; j < M1 + M2; j++) {
                if (edges[i].c > edges[j].c) {
                    Edge temp = edges[i];
                    edges[i] = edges[j];
                    edges[j] = temp;
                }
            }
        }
        // Initialize the disjoint set
        DisjointSet ds;
        for (int i = 0; i < N; i++) {
            ds.parent[i] = i;
            ds.rank[i] = 0;
        }
        int maxProfit = 0, minCost = 0;
        for (int i = 0; i < M1 + M2; i++) {
            if (find(&ds, edges[i].u) != find(&ds, edges[i].v)) {
                unionSet(&ds, edges[i].u, edges[i].v);
                if (i >= M1) {
                    maxProfit += edges[i].c;
                }
                minCost += edges[i].c;
            }
        }
        if (minCost == INF) {
            printf("Impossible\n");
        } else {
            printf("%d %d\n", maxProfit, minCost);
        }
    }
    return 0;
}

